use-scroll-lock-basic.raw:
"use client";

import { useScrollLock } from "@diffgazer/keys";
import { useState } from "react";

function Overlay({ onClose }: { onClose: () => void }) {
  useScrollLock();

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 50,
      }}
    >
      <button
        type="button"
        aria-label="Close overlay"
        onClick={onClose}
        style={{
          position: "absolute",
          inset: 0,
          border: "none",
          padding: 0,
          background: "rgba(0,0,0,0.6)",
          cursor: "pointer",
        }}
      />
      <div style={{ position: "relative", padding: 16, background: "white", color: "black" }}>
        <h3>Overlay</h3>
        <p>Background scroll is locked while this overlay is visible.</p>
        <button type="button" onClick={onClose}>
          Close
        </button>
      </div>
    </div>
  );
}

export default function UseScrollLockBasic() {
  const [open, setOpen] = useState(false);

  return (
    <div style={{ height: 500 }}>
      <p>Scroll status: {open ? "locked" : "unlocked"}</p>
      <button type="button" onClick={() => setOpen(true)}>
        Show Overlay
      </button>
      <p>Scroll down to see content. Opening the overlay locks scroll.</p>
      {open && <Overlay onClose={() => setOpen(false)} />}
    </div>
  );
}

use-scroll-lock-target.raw:
"use client";

import { useScrollLock } from "@diffgazer/keys";
import { useRef, useState } from "react";

export default function UseScrollLockTarget() {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [locked, setLocked] = useState(false);

  // Lock a specific scroll container instead of document.body.
  useScrollLock({ target: scrollRef, enabled: locked });

  return (
    <div>
      <button type="button" onClick={() => setLocked((v) => !v)}>
        {locked ? "Unlock panel" : "Lock panel"}
      </button>

      <div
        ref={scrollRef}
        style={{
          marginTop: 8,
          height: 120,
          overflow: "auto",
          border: "1px solid currentColor",
          padding: 8,
        }}
      >
        {Array.from({ length: 20 }, (_, i) => `Scrollable row ${i + 1}`).map((row) => (
          <p key={row} style={{ margin: "4px 0" }}>
            {row}
          </p>
        ))}
      </div>
      <p>Scrolling inside the panel is blocked while locked; the page itself is untouched.</p>
    </div>
  );
}
